mapper.select:
SELECT COALESCE(MAX(problem_id), 0)
FROM (
	SELECT problem_id
	FROM voj_problems
	WHERE problem_id >= #{problemId}

		AND problem_is_public = 1

	LIMIT #{limit}
) p

SELECT DISTINCT(p.problem_id), problem_name, problem_is_public, (
	SELECT COUNT(*) 
	FROM voj_submissions s 
	WHERE s.problem_id = p.problem_id
) AS total_submission, (
	SELECT COUNT(*) 
	FROM voj_submissions s 
	WHERE s.problem_id = p.problem_id AND s.submission_judge_result = 'AC'
) AS accepted_submission
FROM voj_problems p 
NATURAL JOIN voj_problem_category_relationships pcr

	NATURAL JOIN voj_problem_tag_relationships ptr

WHERE p.problem_id >= #{problemId}

	AND problem_is_public = 1


	AND problem_name LIKE "%"#{keyword}"%"


	AND problem_category_id = #{problemCategoryId}


	AND problem_tag_id = #{problemTagId}

LIMIT #{limit}

mapper.update:
UPDATE voj_problems 
SET problem_is_public = #{isPublic}, problem_name = #{problemName}, problem_difficulty_id = #{problemDifficulty.problemDifficultyId}, problem_time_limit = #{timeLimit}, problem_memory_limit = #{memoryLimit}, problem_description = #{description}, problem_input_format = #{inputFormat}, problem_output_format = #{outputFormat}, problem_sample_input = #{sampleInput}, problem_sample_output = #{sampleOutput}, problem_hint = #{hint} 
WHERE problem_id = #{problemId}

mapper.select:
SELECT checkpoints_version
FROM voj_problems
WHERE problem_id = #{problemId}

mapper.update:
UPDATE voj_problems
SET checkpoints_version = checkpoints_version + 1
WHERE problem_id = #{problemId}
